+# static uint8_t vm_sizeinfo(void)
+# {
+#     uint8_t res = sizeof(bint) == 8;
+#     res |= (sizeof(breal) == 8) << 1;
+#     return res;
+# }
+def vm_sizeinfo():
+    res = 1 if USE_64BIT_INT else 0  # sizeof(bint) == 8
+    res |= (0 if BE_USE_SINGLE_FLOAT else 1) << 1  # sizeof(breal) == 8
+    return res
