+# static void save_header(void *fp)
+# {
+#     uint8_t buffer[8] = { 0 };
+#     buffer[0] = MAGIC_NUMBER1;
+#     buffer[1] = MAGIC_NUMBER2;
+#     buffer[2] = MAGIC_NUMBER3;
+#     buffer[3] = BYTECODE_VERSION;
+#     buffer[4] = vm_sizeinfo();
+#     be_fwrite(fp, buffer, sizeof(buffer));
+# }
+def save_header(fp):
+    buf = bytearray(8)
+    buf[0] = MAGIC_NUMBER1
+    buf[1] = MAGIC_NUMBER2
+    buf[2] = MAGIC_NUMBER3
+    buf[3] = BYTECODE_VERSION
+    buf[4] = vm_sizeinfo()
+    fp.write(bytes(buf))
