+# bclass* be_newclass(bvm *vm, bstring *name, bclass *super)
+# {
+#     bgcobject *gco = be_gcnew(vm, BE_CLASS, bclass);
+#     bclass *obj = cast_class(gco);
+#     bvalue *buf = be_incrtop(vm); /* protect new objects from GC */
