+# ============================================================================
+
+# void be_class_method_bind(bvm *vm, bclass *c, bstring *name, bproto *p, bbool is_static)
+# {
+#     bclosure *cl;
+#     bvalue *attr;
+#     set_fixed(name);
+#     check_members(vm, c);
+#     attr = be_map_insertstr(vm, c->members, name, NULL);
+#     restore_fixed(name);
+#     var_setnil(attr);
