+# static binstance* instance_member(bvm *vm,
+#     binstance *obj, bstring *name, bvalue *dst)
+# {
+#     for (; obj; obj = obj->super) {
+#         bmap *members = obj->_class->members;
+#         if (members) {
+#             bvalue *v = be_map_findstr(vm, members, name);
