+def _newobjself(vm, c):
+    """Create a single instance for class *c* with all member variables set to nil."""
+    obj = binstance()
+    obj.type = BE_INSTANCE
+
+    # Register with GC
+    obj.next = vm.gc.list
+    vm.gc.list = obj
+
+    # Initialize member variable slots to nil
+    obj.members = [bvalue() for _ in range(c.nvar)]
+    obj._class = c
+    obj.super = None
+    obj.sub = None
